class Solution(object):
    def shortestBeautifulSubstring(self, s, k):
        n = len(s)
        ans = ""
        min_len = float('inf')
        for i in range(n):
            ones = 0
            for j in range(i, n):
                if s[j] == '1':
                    ones += 1
                if ones == k:
                    length = j - i + 1
                    sub = s[i:j + 1]
                    if length < min_len or (length == min_len and sub < ans):
                        min_len = length
                        ans = sub
                    break  # shortest from this start found
        return ans
